  "wi": "#7B0041", "west indies": "#7B0041",
  "ban": "#006A4E", "bangladesh": "#006A4E",
};
function getTeamColor(name) {
  if (!name) return "#1E2D6B";
  const n = name.toLowerCase();
  for (const [k, v] of Object.entries(TEAM_COLORS)) {
    if (n.includes(k)) return v;
  }
  return "#1E2D6B";
}

